在方法体内，找到这段逻辑：
```php
if ($record) {
    if ($record->skip_reason && in_array($record->skip_reason, [BackgroundCheckRecordMd::SKIP_OFFLINE, BackgroundCheckRecordMd::SKIP_NO_NEED])) {
        continue;
    }
    if ($record->sent_at) {
        continue;
    }
}
```

改为：
```php
if ($record) {
    if ($record->skip_reason && in_array($record->skip_reason, [BackgroundCheckRecordMd::SKIP_OFFLINE, BackgroundCheckRecordMd::SKIP_NO_NEED])) {
        continue;
    }
    if ($record->skip_reason === BackgroundCheckRecordMd::SKIP_DEFERRED) {
        if ($scene === self::SCENE_CREATE_OFFER) {
            continue; // 发 offer 时已选暂缓，不拦截
        }
        // al_entry 时，归入 deferred 类型提醒
        $workExp = $this->getWorkExperienceByIndex($expArr, $idx);
        $company = $workExp['name'] ?? $workExp['company_name'] ?? ($record->company ?? '');
        $result[] = [
            'work_experience_index' => $idx,
            'company' => $company,
            'segment_type' => self::SEGMENT_TYPE_DEFERRED,
        ];
        continue;
    }
    if ($record->sent_at) {
        continue;
    }
}
```

